import pandas as pd
import numpy as np
from transformers import AutoModelForSequenceClassification, AutoTokenizer
from sentence_transformers import SentenceTransformer, InputExample, SentEmbeddingModel
import torch

# Load company documents into vector database (using sentence embeddings)
class VectorDB:
    def __init__(self):
        self.model = SentenceTransformer('all-MiniLM-L6-v2')

    def embed(self, sentences):
        return self.model.encode(sentences)

db = VectorDB()
doc_embeddings = db.embed(["Document 1 content", "Document 2 content"])

# Load pre-trained language model and tokenizer
tokenizer = AutoTokenizer.from_pretrained("your-pretrained-model")
model = AutoModelForSequenceClassification.from_pretrained("your-pretrained-model")

def get_relevant_context(query):
    # Get sentence embeddings for query
    query_embedding = db.model.encode(query)
    
    # Retrieve documents with cosine similarity > 0.7 (adjust to your liking)
    relevant_docs = []
    for i, doc in enumerate(doc_embeddings):
        similarity = np.dot(query_embedding, doc) / (np.linalg.norm(query_embedding) * np.linalg.norm(doc))
        if similarity > 0.7:
            relevant_docs.append(i)
    
    # Get text from relevant documents
    contexts = []
    for i in relevant_docs:
        contexts.append(["Document", "content"])
    
    # Include all retrieved documents in LLM prompt
    input_ids = tokenizer.encode_plus(
        ["Document 1 content", "Document 2 content"],
        add_special_tokens=True,
        max_length=512,
        return_attention_mask=True,
        return_tensors='pt'
    )
    
    # Generate response using pre-trained language model
    output = model(input_ids=input_ids['input_ids'], attention_mask=input_ids['attention_mask'])
    
    return output.logits

def chatbot():
    while True:
        query = input("Enter your query: ")
        
        # Get relevant context
        relevant_context = get_relevant_context(query)
        
        # Generate response using pre-trained language model and retrieved context
        response = model.generate(relevant_context, max_length=128)
        
        print(response)

chatbot()